import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";

function ViewApplications() {
  const [apps, setApps] = useState([]);
  const navigate = useNavigate();

  const loggedUser =
    JSON.parse(localStorage.getItem("loggedInUser")) || null;

  /* =========================
     LOAD APPLICATIONS
  ========================= */
  useEffect(() => {
    const stored =
      JSON.parse(localStorage.getItem("applications")) || [];

    if (loggedUser?.role === "employee") {
      setApps(
        stored.filter(
          (app) =>
            app.email === loggedUser.username ||
            app.empId === loggedUser.empId
        )
      );
    } else {
      setApps(stored);
    }
  }, [loggedUser]);

  /* =========================
     UPDATE STATUS (ADMIN)
  ========================= */
  const updateStatus = (id, status) => {
    const updated = apps.map((a) =>
      a.id === id ? { ...a, status } : a
    );
    setApps(updated);
    localStorage.setItem("applications", JSON.stringify(updated));
  };

  return (
    <div style={{ marginTop: "25px" }}>
      <h2>
        {loggedUser?.role === "admin"
          ? "Job Applications (Admin)"
          : "My Job Applications"}
      </h2>

      <table className="designation-table">
        <thead>
          <tr>
            <th>S.No</th>
            <th>Employee</th>
            <th>Email</th>
            <th>Job Title</th>
            <th>Status</th>
            <th>Applied Date</th>
            {loggedUser?.role === "admin" && <th>Action</th>}
          </tr>
        </thead>

        <tbody>
          {apps.length === 0 ? (
            <tr>
              <td colSpan="7" style={{ textAlign: "center" }}>
                No Applications Found
              </td>
            </tr>
          ) : (
            apps.map((a, index) => (
              <tr key={a.id}>
                <td>{index + 1}</td>
                <td>{a.employeeName || "Unknown"}</td>
                <td>{a.email}</td>
                <td>{a.jobTitle}</td>

                <td>
                  <span
                    style={{
                      padding: "6px 12px",
                      borderRadius: "6px",
                      fontWeight: "600",
                      color: "white",
                      background:
                        a.status === "Approved"
                          ? "green"
                          : a.status === "Rejected"
                          ? "red"
                          : a.status === "OFFER_SENT"
                          ? "#64748b"
                          : "#94a3b8",
                    }}
                  >
                    {a.status}
                  </span>
                </td>

                <td>{a.appliedDate || "--"}</td>

                {loggedUser?.role === "admin" && (
                  <td style={{ display: "flex", gap: "10px" }}>
                    {a.status === "Pending" && (
                      <>
                        <button
                          onClick={() =>
                            updateStatus(a.id, "Approved")
                          }
                        >
                          Approve
                        </button>
                        <button
                          onClick={() =>
                            updateStatus(a.id, "Rejected")
                          }
                        >
                          Reject
                        </button>
                      </>
                    )}

                    {a.status === "Approved" && (
                      <button
                        onClick={() =>
                          navigate(
                            `/dashboard/recruitment/offer-letter/${a.id}`
                          )
                        }
                      >
                        Offer Letter
                      </button>
                    )}

                    {a.status === "OFFER_SENT" && (
                      <>
                        <button
                          onClick={() =>
                            navigate(
                              `/dashboard/recruitment/offer-letter/${a.id}`
                            )
                          }
                        >
                          Edit Offer
                        </button>
                        <button
                          onClick={() =>
                            navigate(
                              `/dashboard/recruitment/offer-preview/${a.id}`
                            )
                          }
                        >
                          View Offer
                        </button>
                      </>
                    )}
                  </td>
                )}
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}

export default ViewApplications;
